import './App.css';
import {
  BrowserRouter as Router,
  Switch,
  Route,
} from "react-router-dom";
import { Navbar } from './components/Navbar';
import { Home } from './components/Home';
import { Contact } from './components/Contact';
import { About } from './components/About';
import { CartPage } from './components/CartPage';
import { ProductDetail } from './components/ProductDetail';
import { Checkout } from './components/Checkout';
import { Category } from './components/Category';
import { Login } from './components/Login';
import { Signup } from './components/Signup';
import { Receipe } from './components/Receipe';
import { Forgot } from './components/Forgot';
import { Reset } from './components/Reset';
import { RecBDetails } from './components/RecBDetails';
import { RecNDetails } from './components/RecNDetails';
import UploadProduct from './components/Upload/UploadProduct';

function App() {
  return (
    <>
      <Router>
        <Navbar />
        <Switch>
          <Route exact path="/">
            <Home />
          </Route>
          <Route exact path="/contacts">
            <Contact />
          </Route>
          <Route exact path="/about">
            <About />
          </Route>
          <Route exact path="/cartpage">
            <CartPage />
          </Route>
          <Route exact path="/productdetail">
            <ProductDetail />
          </Route>
          <Route exact path="/checkout">
            <Checkout />
          </Route>
          <Route exact path="/category">
            <Category />
          </Route>
          <Route exact path="/login">
            <Login />
          </Route>
          <Route exact path="/signin">
            <Signup />
          </Route>
          <Route exact path="/receipe">
            <Receipe />
          </Route>
          <Route exact path="/forgot">
            <Forgot />
          </Route>
          <Route exact path="/reset">
            <Reset />
          </Route>
          <Route exact path="/biryani">
            <RecBDetails/>
          </Route>
          <Route exact path="/noodles">
            <RecNDetails />
          </Route>
          <Route exact path="/product/upload">
            <UploadProduct />
          </Route>
        </Switch>
      </Router>
    </>
  );
}

export default App;
